export function getCareerExtended(slug: string): CareerExtended | undefined {
  return CAREERS_EXTENDED.find(c => c.slug === slug)
}

export const CAREER_EXTENDED_SLUGS = CAREERS_EXTENDED.map(c => c.slug)
